#include <stdio.h>
#include <math.h>
int isPrime(int n) {
    if (n <= 1) return 0;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) return 0;
    }
    return 1;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int x, y;
        scanf("%d %d", &x, &y);
        int ans = 1e9;
        for (int i = 0; i < 100000; i++) {
            int num = i * i + i + 1;
            if (isPrime(num)) {
                int dx = abs(i - x);
                int dy = abs(i - y);
                ans = (ans < dx + dy) ? ans : dx + dy;
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

