using namespace std;
bool isPrime(int n) {
    if (n <= 1) return false;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) return false;
    }
    return true;
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int x, y;
        cin >> x >> y;
        int ans = 1e9;
        for (int i = 0; i < 100000; i++) {
            int num = i * i + i + 1;
            if (isPrime(num)) {
                int dx = abs(i - x);
                int dy = abs(i - y);
                ans = min(ans, dx + dy);
            }
        }
        cout << ans << endl;
    }
    return 0;
}

